}

public class Person {
    private String name;
    private char sex;
    private int age;
    public Person(String name, char sex, int age) {
        this.name = name;
        this.sex = sex;
        this.age = age;
    }
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public char getSex() { return sex; }
    public void setSex(char sex) { this.sex = sex; }
    public int getAge() { return age; }
    public void setAge(int age) { this.age = age; }
    public void saying(Person per, String msg) {
        System.out.println(this.name + "对" + per.getName() + "说：\"" + msg + "\"");
    }
}
public interface ITask {
    void working();
    void rest();
    void show();
}
public class Student extends Person implements ITask {
    private String id;
    public Student(String name, char sex, int age, String id) {
        super(name, sex, age);
        this.id = id;
    }
    @Override
    public void working() {
        System.out.println(this.getName() + "正在学习。");
    }
    @Override
    public void rest() {
        System.out.println(this.getName() + "正在休息。");
    }
    @Override
    public void show() {
        System.out.println("姓名：" + this.getName() + "，性别：" + this.getSex() + "，年龄：" + this.getAge() + "，学号：" + this.id + "。");
    }
    public void reading(String book) {
        System.out.println(this.getName() + "读：" + book + "。");
    }
}
public class Teacher extends Person implements ITask {
    private String department;
    public Teacher(String name, char sex, int age, String department) {
        super(name, sex, age);
        this.department = department;
    }
    @Override
    public void working() {
        System.out.println(this.getName() + "正在上课。");
    }
    @Override
    public void rest() {
        System.out.println(this.getName() + "正在休息。");
    }
    @Override
    public void show() {
        System.out.println("姓名：" + this.getName() + "，性别：" + this.getSex() + "，年龄：" + this.getAge() + "，部门：" + this.department + "。");
    }
    public void teaching(Student std, String course) {
        System.out.println(this.getName() + "正在向" + std.getName() + "讲授" + course + "课程。");
    }
}
public class Demo {
    public static void main(String[] args) {
        Student sun = new Student("孙悟空", '男', 22, "190010987");
        Teacher tang = new Teacher("唐僧", '男', 26, "国学系");
        System.out.println("----------测试Student类----------");
        sun.show();
        sun.reading("西游记");
        sun.working();
        sun.rest();
        sun.saying(tang, "师傅你注意安全，俺老孙去去就回。");
        System.out.println("----------测试Teacher类----------");
        tang.teaching(sun, "除妖记");
        tang.show();
        tang.saying(sun, "悟空你又调皮了！");
    }
}

